class CompositeMediaService {
    private var repository: MediaAssetRepository
    private var compositeAsset: AVMutableComposition?

    init(repository: MediaAssetRepository) {
        self.repository = repository
    }

    func createCompositeAsset(with assets: [MediaAsset]) -> AVMutableComposition? {
        compositeAsset = AVMutableComposition()
        for asset in assets {
            guard let asset = AVAsset(url: asset.url) else { continue }
            let track = asset.tracks(withMediaType: .video)[0]
            let videoCompositionTrack = compositeAsset!.addMutableTrack(withMediaType: .video, preferredTrackID: kCMPersistentTrackID_Invalid)
            try? videoCompositionTrack?.insertTimeRange(CMTimeRangeMake(kCMTimeZero, asset.duration), of: track, at: compositeAsset!.duration)
        }
        return compositeAsset
    }
